function rich(text) {
  const s = String(text || '');
  const parts = [];
  const re = /\*\*(.+?)\*\*/g;
  let last = 0, m;
  while ((m = re.exec(s)) !== null) {
    if (m.index > last) parts.push({ type:'text', text:{ content: s.slice(last, m.index) } });
    parts.push({ type:'text', text:{ content: m[1] }, annotations:{ bold:true } });
    last = m.index + m[0].length;
  }
  if (last < s.length) parts.push({ type:'text', text:{ content: s.slice(last) } });
  if (!parts.length) parts.push({ type:'text', text:{ content: s } });
  const out = [];
  for (const p of parts) {
    const c = p.text.content;
    if (c.length <= 2000) out.push(p);
    else for (let i=0;i<c.length;i+=2000) out.push({ ...p, text:{ content: c.slice(i,i+2000) } });
  }
  return out;
}
function h(type, text){ return { object:'block', type, [type]:{ rich_text: rich(text) } }; }

function mdToBlocks(md) {
  const lines = String(md || '').split('\n');
  const blocks = [];
  let table = null;
  const flush = () => {
    if (!table || !table.length) { table = null; return; }
    const rows = table
      .filter(r => !/^\s*\|?\s*:?-{2,}/.test(r))
      .map(r => r.replace(/^\s*\|/, '').replace(/\|\s*$/, '').split('|').map(c => c.trim()));
    if (!rows.length) { table = null; return; }
    const width = Math.max(...rows.map(r => r.length));
    blocks.push({
      object:'block', type:'table',
      table: {
        table_width: width, has_column_header: true, has_row_header: false,
        children: rows.map(cells => ({
          object:'block', type:'table_row',
          table_row: { cells: Array.from({ length: width }, (_, k) => (cells[k] && cells[k].trim()) ? rich(cells[k]) : []) }
        }))
      }
    });
    table = null;
  };
  for (const raw of lines) {
    const line = raw.replace(/\s+$/, '');
    if (/^\s*\|.*\|\s*$/.test(line)) { (table = table || []).push(line); continue; }
    if (table) flush();
    if (!line.trim()) continue;
    let m;
    if ((m = line.match(/^(#{1,6})\s+(.*)/))) { const lvl = Math.min(m[1].length, 3); blocks.push(h('heading_' + lvl, m[2])); }
    else if ((m = line.match(/^\s*[-•]\s+(.*)/))) blocks.push({ object:'block', type:'bulleted_list_item', bulleted_list_item:{ rich_text: rich(m[1]) } });
    else if ((m = line.match(/^\s*\d+\.\s+(.*)/))) blocks.push({ object:'block', type:'numbered_list_item', numbered_list_item:{ rich_text: rich(m[1]) } });
    else blocks.push({ object:'block', type:'paragraph', paragraph:{ rich_text: rich(line) } });
  }
  if (table) flush();
  return blocks;
}

const wh = $('Webhook').first().json.body;
let summary = $json.choices?.[0]?.message?.content || '';

// Titolo: prima l'H1 del riassunto (LLM, sempre presente), poi fallback
const h1 = summary.match(/^\s*#\s+(.+)/);
const title = (h1 && h1[1].trim()) || wh.filename || ('Riunione ' + new Date(wh.startTime).toLocaleDateString('it-IT'));

// togli l'H1 dal corpo (è già nel titolo)
summary = summary.replace(/^\s*#\s+.+\r?\n?/, '');

const dateIso = new Date(wh.startTime).toISOString();

const all = mdToBlocks(summary);
const first = all.slice(0, 100);
const rest = [];
for (let i = 100; i < all.length; i += 100) rest.push(all.slice(i, i + 100));

return [{
  json: {
    createBody: {
      parent: { database_id: 'YOUR_NOTION_DATABASE_ID' },
      properties: {
        'Name': { title: [{ text: { content: title } }] },
        'Event time': { date: { start: dateIso } }
      },
      children: first
    },
    restBatches: rest
  }
}];

const pageId = $json.id;
const rest = $('Code Notion').first().json.restBatches || [];
return rest.map((blocks, i) => ({ json: { pageId, batchIndex: i, children: blocks } }));
